import click
from click.testing import CliRunner

@click.command()
@click.option("--protocol", type=click.Choice(["http", "https"]), default="http")
@click.option("--port", default={"--protocol": {"http": 80, "https": 443}})
def serve(protocol, port):
    click.echo(f"{protocol}://localhost:{port}")

runner = CliRunner()

r = runner.invoke(serve, [])
print(repr(r.output), r.exit_code, r.exception)

r = runner.invoke(serve, ["--protocol", "https"])
print(repr(r.output), r.exit_code, r.exception)

r = runner.invoke(serve, ["--protocol", "https", "--port", "9999"])
print(repr(r.output), r.exit_code)

@click.command()
@click.option("--env", type=click.Choice(["dev", "staging", "prod"]), default="dev")
@click.option("--debug", is_flag=True)
@click.option(
    "--log-level",
    default={
        "--env": {"dev": "DEBUG", "staging": "INFO", "prod": "ERROR"},
        "--debug": {"True": "DEBUG"},
    },
)
def deploy(env, debug, log_level):
    click.echo(f"Deploying to {env} with log level {log_level} (debug={debug})")

r = runner.invoke(deploy, ["--env", "prod"])
print(repr(r.output), r.exit_code, r.exception)

r = runner.invoke(deploy, ["--env", "prod", "--debug"])
print(repr(r.output), r.exit_code, r.exception)

# help text check
r = runner.invoke(serve, ["--help"])
print(r.output)

@click.command()
